module top_module(
    input clk,
    input load,
    input [3:0] in,
    output [3:0] out
);reg [3:0] shift_reg;

    always @(posedge clk) begin
        if (load) begin
            shift_reg <= in;
        end else begin
            shift_reg <= {shift_reg[2:0], 1'b0};
        end
    end

    assign out = shift_reg;

endmodule
